5309			for {
5310				rel := strings.Index(lower[offset:], keyword)
5311				if rel < 0 {
5312					break
5313				}
5314				start := offset + rel
5315				before := previousNonSpace(content, start)
5316				if before >= 0 && content[before] != ',' && content[before] != '(' {
5317					offset = start + len(keyword)
